import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(COMMA, DOUBLE_QUOTE_CHAR, null, null, null, false, true, CRLF,
                                  null, null, null, false, false, false, false, false);
    }

    @Test
    public void testEquals_SameObject() {
        assertTrue(csvFormat.equals(csvFormat));
    }

    @Test
    public void testEquals_NullObject() {
        assertFalse(csvFormat.equals(null));
    }

    @Test
    public void testEquals_DifferentClass() {
        assertFalse(csvFormat.equals("Not a CSVFormat object"));
    }

    @Test
    public void testEquals_EqualObjects() {
        CSVFormat other = new CSVFormat(COMMA, DOUBLE_QUOTE_CHAR, null, null, null, false, true, CRLF,
                                        null, null, null, false, false, false, false, false);
        assertTrue(csvFormat.equals(other));
    }

    @Test
    public void testEquals_DifferentDelimiter() {
        CSVFormat other = new CSVFormat(TAB, DOUBLE_QUOTE_CHAR, null, null, null, false, true, CRLF,
                                        null, null, null, false, false, false, false, false);
        assertFalse(csvFormat.equals(other));
    }

    // Add more test cases for other fields comparison

